import { useAuth } from '../context/AuthContext';
import axiosInstance from '../axiosConfig';

const TourList = ({ tours, setTours, setEditingTour }) => {
  const { user } = useAuth();

  const handleDelete = async (e, tourId) => {
    // 阻止事件冒泡，防止點擊刪除按鈕時也觸發編輯彈窗
    e.stopPropagation(); 

    if (!window.confirm("Are you sure you want to delete this tour package?")) return;

    try {
      await axiosInstance.delete(`/api/tours/${tourId}`, {
        headers: { Authorization: `Bearer ${user.token}` },
      });
      // 成功後過濾掉被刪除的項目
      setTours(tours.filter((tour) => tour._id !== tourId));
      alert('Tour deleted successfully!');
    } catch (error) {
      console.error(error);
      alert('Failed to delete tour. Please check your token.');
    }
  };

  return (
    <div className="space-y-4"> {/* 手機版通常是垂直排列 */}
      {tours.length === 0 ? (
        <div className="text-center py-10 text-gray-400 text-sm">
          No tours available yet.
        </div>
      ) : (
        tours.map((tour) => (
          <div 
            key={tour._id} 
            onClick={() => setEditingTour(tour)} // 點擊整塊卡片進入編輯
            className="bg-white p-3 flex items-center space-x-4 border border-gray-100 rounded-2xl shadow-sm active:scale-95 transition-transform cursor-pointer relative"
          >
            {/* 左側：真實圖片區 */}
            <div className="w-20 h-20 flex-shrink-0 rounded-xl overflow-hidden bg-indigo-50 border border-gray-50">
              {tour.imageUrl ? (
                <img 
                  src={tour.imageUrl} 
                  alt={tour.title} 
                  className="w-full h-full object-cover"
                />
              ) : (
                <div className="w-full h-full flex items-center justify-center text-3xl">
                  🏝️
                </div>
              )}
            </div>

            {/* 中間：文字資訊 */}
            <div className="flex-1 min-w-0 pr-12">
              <div className="flex items-center space-x-2">
                <h3 className="font-bold text-gray-800 text-base truncate">{tour.title}</h3>
              </div>
              <p className="text-gray-400 text-xs mt-1 truncate">{tour.location || 'Australia'}</p>

              <div className="mt-3 flex items-center justify-between">
                {/* 價格標籤 */}
                <span className={`px-3 py-1 rounded-lg text-xs font-bold ${tour.status === 'Available' ? 'bg-emerald-500 text-white' : 'bg-red-400 text-white'}`}>
                  {tour.status === 'Available' ? `AUD ${tour.price}` : 'Sold Out'}
                </span>
              </div>
            </div>

            {/* 右側：刪除按鈕 (做成小圖示避開中間資訊) */}
            <button
              onClick={(e) => handleDelete(e, tour._id)}
              className="absolute top-3 right-3 p-2 bg-red-50 text-red-400 rounded-full hover:bg-red-100 transition"
              title="Delete"
            >
              🗑️
            </button>
          </div>
        ))
      )}
    </div>
  );
};

export default TourList;
